SET NAMES utf8mb4;
USE `my_blog`;
START TRANSACTION;

































































UPDATE `blog_article_tag` SET `deleted_at`='2026-05-08 23:01:22',`updated_at`='2026-05-08 23:01:22' WHERE `article_id` IN (200000, 200001, 200002, 200003, 200004, 200005, 200006, 200007, 200008, 200009, 200010, 200011, 200012, 200013, 200014, 200015, 200016, 200017, 200018, 200019, 200020, 200021, 200022, 200023, 200024, 200025, 200026, 200027, 200028, 200029, 200030, 200031, 200032, 200033, 200034, 200035, 200036, 200037, 200038, 200039, 200040, 200041, 200042, 200043, 200044, 200045, 200046, 200047, 200048, 200049, 200050, 200051, 200052, 200053, 200054, 200055, 200056, 200057, 200058, 200059);


UPDATE `blog_column_article` SET `deleted_at`='2026-05-08 23:01:22',`updated_at`='2026-05-08 23:01:22' WHERE `column_id`=9200002;


UPDATE `blog_topic_article` SET `deleted_at`='2026-05-08 23:01:22',`updated_at`='2026-05-08 23:01:22' WHERE `topic_id` IN (9302001, 9302002, 9302003, 9302004, 9302005);


UPDATE `blog_tag` t SET `use_count` = (SELECT COUNT(*) FROM `blog_article_tag` atg WHERE atg.`tag_name` = t.`name` AND atg.`deleted_at` IS NULL) WHERE t.`name` IN ('一些领域算法', '其它算法相关', '常见排序算法', '数据结构基础', '架构设计', '算法', '算法思想');

UPDATE `blog_column` c SET `article_count` = (SELECT COUNT(*) FROM `blog_column_article` ca INNER JOIN `blog_article` a ON a.`id` = ca.`article_id` WHERE ca.`column_id` = c.`id` AND ca.`deleted_at` IS NULL AND a.`deleted_at` IS NULL AND a.`status` = 'PUBLISHED') WHERE c.`id` IN (9200002);

UPDATE `blog_topic` t SET `article_count` = (SELECT COUNT(*) FROM `blog_topic_article` ta INNER JOIN `blog_article` a ON a.`id` = ta.`article_id` WHERE ta.`topic_id` = t.`id` AND ta.`deleted_at` IS NULL AND a.`deleted_at` IS NULL AND a.`status` = 'PUBLISHED') WHERE t.`id` IN (9302001, 9302002, 9302003, 9302004, 9302005);

COMMIT;
